"  int _ezkarTab = 0;

  // Dualar Tool state variables
  int _dualarTab = 0; // 0: Kur'an Duaları, 1: Hadis Duaları
  bool _showOnlyFavorites = false;
  List<String> _favoriteDualar = [];
  String _dualarSearchQuery = "";
  bool _isSearchingDualar = false;
  final TextEditingController _dualarSearchController = TextEditingController();

  Future<void> _loadFavoriteDualar() async {
    final prefs = await SharedPreferences.getInstance();
    if (mounted) {
      setState(() {
        _favoriteDualar = prefs.getStringList('favorite_dualar') ?? [];
      });
    }
  }

  Future<void> _toggleFavoriteDua(String id) async {
    final prefs = await SharedPreferences.getInstance();
    setState(() {
      if (_favoriteDualar.contains(id)) {
        _favoriteDualar.remove(id);
      } else {
        _favoriteDualar.add(id);
      }
    });
    await prefs.setStringList('favorite_dualar', _favoriteDualar);
  }

  @override
  void initState() {
    super.initState();
    _initMosques();
    _loadLocationName();
    if (widget.toolId == 'yakindaki-camiler' || widget.toolId == 'kible-bulucu') {
      _getUserLocation();
    }
    if (widget.toolId == 'namaz-vakitleri-aylik') {
      _loadMonthlyTimes();
    }
    _initAudio();
    _loadZikirState();
    _loadDuaList();
    _loadQuestionList();
    _loadKazaState();
    _loadQuranLastRead();
    _loadFavoriteDualar();
  }"

